class Solution:
    def goodDaysToRobBank(self, security, time):
        n = len(security)
        res = []
        for i in range(n):
            if i - time < 0 or i + time >= n:
                continue
            ok = True
            for j in range(i - time, i):
                if security[j] < security[j + 1]:
                    ok = False
                    break
            if ok:
                for j in range(i, i + time):
                    if security[j] > security[j + 1]:
                        ok = False
                        break
            if ok:
                res.append(i)
        return res

