class Solution:
    def goodDaysToRobBank(self, security, time):
        n = len(security)
        if time == 0:
            return list(range(n))
        nonincreasing = [0] * n
        nondecreasing = [0] * n
        for i in range(1, n):
            if security[i] <= security[i - 1]:
                nonincreasing[i] = nonincreasing[i - 1] + 1
        for i in range(n - 2, -1, -1):
            if security[i] <= security[i + 1]:
                nondecreasing[i] = nondecreasing[i + 1] + 1
        return [i for i in range(n) if nonincreasing[i] >= time and nondecreasing[i] >= time]

solutions.javascript:
var goodDaysToRobBank = function(security, time) {
    const n = security.length;
    if (time === 0) {
        const all = [];
        for (let i = 0; i < n; i++) all.push(i);
        return all;
    }
    const nonincreasing = new Array(n).fill(0);
    const nondecreasing = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        if (security[i] <= security[i - 1]) nonincreasing[i] = nonincreasing[i - 1] + 1;
    }
    for (let i = n - 2; i >= 0; i--) {
        if (security[i] <= security[i + 1]) nondecreasing[i] = nondecreasing[i + 1] + 1;
    }
    const res = [];
    for (let i = 0; i < n; i++) {
        if (nonincreasing[i] >= time && nondecreasing[i] >= time) res.push(i);
    }
    return res;
};
